/**
 * virtual-scroll-grid — cục bộ (unpkg.com/virtual-scroll-grid@1.0.0 không tồn tại).
 * API: VirtualScrollGrid.mountTableBody(...) | mountDivList(...)
 */
(function (global) {
    'use strict';
    function clamp(n, a, b) {
        return Math.max(a, Math.min(b, n));
    }
    function mountTableBody(opts) {
        var scrollEl = opts.scrollEl;
        var tbody = opts.tbody;
        var itemHeight = Math.max(24, opts.itemHeight || 72);
        var overscan = opts.overscan == null ? 5 : opts.overscan;
        var totalCount = 0;
        var renderRows = opts.renderRows;
        var colspan = opts.colspan || 8;
        var raf = null;
        function spacerTr(px) {
            if (px <= 0) return '';
            return (
                '<tr class="vsg-spacer" aria-hidden="true"><td colspan="' +
                colspan +
                '" style="padding:0;border:none;height:' +
                px +
                'px;line-height:0;font-size:0;vertical-align:top">&nbsp;</td></tr>'
            );
        }
        function paint() {
            if (!scrollEl || !tbody || !renderRows) return;
            var n = totalCount;
            if (n === 0) {
                tbody.innerHTML = renderRows(0, 0);
                return;
            }
            var st = scrollEl.scrollTop;
            var vh = scrollEl.clientHeight || 400;
            var start = Math.floor(st / itemHeight) - overscan;
            var end = Math.ceil((st + vh) / itemHeight) + overscan;
            start = clamp(start, 0, n);
            end = clamp(end, start, n);
            var topPad = start * itemHeight;
            var botPad = (n - end) * itemHeight;
            tbody.innerHTML = spacerTr(topPad) + renderRows(start, end) + spacerTr(botPad);
        }
        function onScroll() {
            if (raf) cancelAnimationFrame(raf);
            raf = requestAnimationFrame(function () {
                raf = null;
                paint();
            });
        }
        scrollEl.addEventListener('scroll', onScroll, { passive: true });
        window.addEventListener('resize', onScroll);
        return {
            update: function (count, fn) {
                totalCount = count | 0;
                if (typeof fn === 'function') renderRows = fn;
                onScroll();
            },
            refresh: onScroll,
            destroy: function () {
                scrollEl.removeEventListener('scroll', onScroll);
                window.removeEventListener('resize', onScroll);
                if (raf) cancelAnimationFrame(raf);
            },
        };
    }
    function mountDivList(opts) {
        var scrollEl = opts.scrollEl;
        var itemHeight = Math.max(20, opts.itemHeight || 64);
        var overscan = opts.overscan == null ? 5 : opts.overscan;
        var totalCount = 0;
        var renderItems = opts.renderItems;
        var raf = null;
        var phantom = document.createElement('div');
        phantom.className = 'vsg-phantom';
        phantom.style.cssText = 'position:relative;min-height:1px';
        var content = document.createElement('div');
        content.className = 'vsg-window';
        content.style.cssText = 'position:absolute;left:0;right:0;top:0;will-change:transform';
        phantom.appendChild(content);
        scrollEl.innerHTML = '';
        scrollEl.appendChild(phantom);
        function paint() {
            if (!renderItems) return;
            var n = totalCount;
            if (n === 0) {
                phantom.style.height = '0px';
                content.style.transform = 'translateY(0px)';
                content.innerHTML = renderItems(0, 0);
                return;
            }
            phantom.style.height = n * itemHeight + 'px';
            var st = scrollEl.scrollTop;
            var vh = scrollEl.clientHeight || 300;
            var start = Math.floor(st / itemHeight) - overscan;
            var end = Math.ceil((st + vh) / itemHeight) + overscan;
            start = clamp(start, 0, n);
            end = clamp(end, start, n);
            content.style.transform = 'translateY(' + start * itemHeight + 'px)';
            content.innerHTML = renderItems(start, end);
        }
        function onScroll() {
            if (raf) cancelAnimationFrame(raf);
            raf = requestAnimationFrame(function () {
                raf = null;
                paint();
            });
        }
        scrollEl.addEventListener('scroll', onScroll, { passive: true });
        window.addEventListener('resize', onScroll);
        return {
            update: function (count, fn) {
                totalCount = count | 0;
                if (typeof fn === 'function') renderItems = fn;
                onScroll();
            },
            refresh: onScroll,
            destroy: function () {
                scrollEl.removeEventListener('scroll', onScroll);
                window.removeEventListener('resize', onScroll);
                if (raf) cancelAnimationFrame(raf);
            },
        };
    }
    global.VirtualScrollGrid = { mountTableBody: mountTableBody, mountDivList: mountDivList };
})(typeof window !== 'undefined' ? window : globalThis);
